import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Briefcase, Calendar, ArrowRight } from 'lucide-react';

const Experience = () => {
  const navigate = useNavigate();

  const experiences = [
    {
      id: 0,
      company: "DigitalBee Labs",
      role: "Trainer Software Engineer",
      period: "2024 - Present",
      description: "Currently training and mentoring junior developers in modern web technologies and software engineering best practices.",
      skills: ["React", "JavaScript", "Teaching", "Mentoring", "Web Development"]
    }
  ];

  return (
    <section id="experience" className="py-24 bg-slate-100 dark:bg-darkCard/30">
      <div className="container mx-auto px-6">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold mb-4">Work Experience</h2>
          <div className="w-20 h-1.5 bg-primary mx-auto rounded-full"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 max-w-6xl mx-auto">
          {experiences.map((exp, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
              onClick={() => navigate(`/experience/${exp.id}`)}
              className="h-full cursor-pointer group"
            >
              <div className="glass p-8 rounded-3xl shadow-lg border border-primary/10 h-full hover:shadow-2xl hover:border-primary/30 transition-all duration-300 transform hover:-translate-y-2">
                <div className="flex items-start justify-between mb-6">
                  <div className="flex-1">
                    <div className="inline-block mb-4">
                      <span className="text-xs font-bold uppercase px-3 py-1 bg-primary/10 text-primary rounded-full border border-primary/20">
                        {exp.period}
                      </span>
                    </div>
                    <h3 className="text-xl font-bold mb-2 group-hover:text-primary transition-colors">
                      {exp.role}
                    </h3>
                  </div>
                </div>

                <div className="flex items-center gap-2 text-slate-500 mb-4 pb-4 border-b border-slate-200 dark:border-slate-700">
                  <Briefcase size={16} />
                  <span className="font-medium text-sm">{exp.company}</span>
                </div>

                <p className="text-slate-600 dark:text-slate-400 mb-6 text-sm leading-relaxed line-clamp-3">
                  {exp.description}
                </p>

                <div className="flex flex-wrap gap-2 mb-6">
                  {exp.skills.slice(0, 3).map(skill => (
                    <span key={skill} className="px-2 py-1 bg-primary/5 text-primary text-xs font-semibold rounded-lg border border-primary/10">
                      {skill}
                    </span>
                  ))}
                  {exp.skills.length > 3 && (
                    <span className="px-2 py-1 bg-primary/5 text-primary text-xs font-semibold rounded-lg border border-primary/10">
                      +{exp.skills.length - 3} more
                    </span>
                  )}
                </div>

                <div className="flex items-center gap-2 text-primary font-semibold text-sm group-hover:gap-3 transition-all">
                  <span>View Details</span>
                  <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
